const body = $json.body ?? $json;
const type = (body.type ?? '').toString().toLowerCase();

if (type !== 'exercise_submission') {
  return [{
    json: {
      approved: false,
      status: 'rejected',
      score: 0,
      coachReply: 'Type d\'evenement non supporte pour cette revue.',
      provider: 'n8n-pedago-groq',
      issues: [`expected exercise_submission, received ${type || 'unknown'}`],
      recommendations: ['Utiliser le webhook pedago dedie a la revue d exercice.'],
      receivedAt: new Date().toISOString()
    }
  }];
}

const assets = Array.isArray(body.assets)
  ? body.assets.filter((asset) => asset && typeof asset.url === 'string')
  : Array.isArray(body.assetUrls)
    ? body.assetUrls.filter((url) => typeof url === 'string').map((url, index) => ({ id: `asset-${index + 1}`, url }))
    : typeof body.assetUrl === 'string' && body.assetUrl
      ? [{ id: 'asset-1', url: body.assetUrl }]
      : [];

const expectedAssetCount = Math.max(1, Number(body.expectedAssetCount ?? 1) || 1);

return [{
  json: {
    ...body,
    type,
    assets,
    assetCount: assets.length,
    expectedAssetCount,
    evaluationChecklist: Array.isArray(body.evaluationChecklist) ? body.evaluationChecklist : [],
    rejectionHints: Array.isArray(body.rejectionHints) ? body.rejectionHints : [],
    evaluationPrompt: String(body.evaluationPrompt ?? '').trim(),
    evaluationObjective: String(body.evaluationObjective ?? '').trim(),
    receivedAt: new Date().toISOString()
  }
}];

const moduleId = String($json.moduleId ?? '').trim();
const checklist = Array.isArray($json.evaluationChecklist) ? $json.evaluationChecklist : [];
const hints = Array.isArray($json.rejectionHints) ? $json.rejectionHints : [];
const assets = Array.isArray($json.assets) ? $json.assets : [];
const expectedAssetCount = Math.max(1, Number($json.expectedAssetCount ?? 1) || 1);
const missingEvidence = assets.length < expectedAssetCount;

if (missingEvidence) {
  return [{
    json: {
      approved: false,
      status: 'needs_revision',
      score: 20,
      coachReply: `Preuves insuffisantes pour corriger le module ${moduleId || 'inconnu'}.`,
      provider: 'n8n-pedago-precheck',
      issues: [`Preuves visuelles insuffisantes: ${assets.length}/${expectedAssetCount}.`],
      recommendations: [
        `Ajoutez ${expectedAssetCount - assets.length} image(s) supplementaire(s) avant nouvelle analyse.`,
        ...(hints.slice(0, 2))
      ],
      receivedAt: $json.receivedAt,
      moduleId,
      assetCount: assets.length,
      expectedAssetCount,
      skippedGroq: true
    }
  }];
}

const model = String(process.env.GROQ_VISION_MODEL || 'meta-llama/llama-4-scout-17b-16e-instruct').trim();
const schema = {
  type: 'object',
  additionalProperties: false,
  required: ['approved', 'status', 'score', 'coachReply', 'issues', 'recommendations'],
  properties: {
    approved: { type: 'boolean' },
    status: { type: 'string', enum: ['approved', 'needs_revision', 'rejected', 'error'] },
    score: { type: 'number', minimum: 0, maximum: 100 },
    coachReply: { type: 'string' },
    issues: {
      type: 'array',
      items: { type: 'string' },
      maxItems: 5
    },
    recommendations: {
      type: 'array',
      items: { type: 'string' },
      maxItems: 5
    }
  }
};

const userText = [
  `Module: ${moduleId || 'unknown'}`,
  `Objectif: ${String($json.evaluationObjective || 'Evaluer la soumission selon la consigne.')}`,
  `Prompt de correction: ${String($json.evaluationPrompt || '')}`,
  `Nombre d'images attendues: ${expectedAssetCount}`,
  `Nombre d'images recues: ${assets.length}`,
  checklist.length ? `Checklist: ${checklist.map((item, index) => `${index + 1}. ${item}`).join(' | ')}` : '',
  hints.length ? `Pistes de refus/action: ${hints.join(' | ')}` : '',
  'Analyse toutes les images ensemble. Ne valide que si la consigne pedagogique est visiblement respectee. Sois strict, concret, et actionnable.'
].filter(Boolean).join('\n');

const input = [
  {
    role: 'user',
    content: [
      { type: 'input_text', text: userText },
      ...assets.map((asset) => ({ type: 'input_image', image_url: asset.url }))
    ]
  }
];

return [{
  json: {
    ...$json,
    groqModel: model,
    groqRequestBody: {
      model,
      temperature: 0.2,
      max_output_tokens: 700,
      instructions: 'Tu es un maitre pedagogique photo. Tu corriges un exercice a partir d images et tu dois retourner uniquement un JSON conforme au schema fourni. Refuse les validations molles. Si la preuve est incomplete ou ambiguë, mets approved=false.',
      input,
      text: {
        format: {
          type: 'json_schema',
          name: 'exercise_review',
          schema
        }
      }
    }
  }
}];

if ($json.skippedGroq) {
  return [{ json: $json }];
}

const apiKey = String(process.env.GROQ_API_KEY || '').trim();
if (!apiKey) {
  return [{
    json: {
      approved: false,
      status: 'error',
      score: 0,
      coachReply: 'GROQ_API_KEY absent sur l instance n8n pedagogique.',
      provider: 'n8n-pedago-groq',
      issues: ['Missing GROQ_API_KEY environment variable.'],
      recommendations: ['Ajouter GROQ_API_KEY dans les variables d environnement du service pedago.'],
      receivedAt: $json.receivedAt,
      groqModel: $json.groqModel,
      skippedGroq: true
    }
  }];
}

const timeoutMs = Math.max(5000, Number(process.env.GROQ_TIMEOUT_MS || 45000) || 45000);
const response = await fetch('https://api.groq.com/openai/v1/responses', {
  method: 'POST',
  headers: {
    'content-type': 'application/json',
    authorization: `Bearer ${apiKey}`
  },
  body: JSON.stringify($json.groqRequestBody),
  signal: AbortSignal.timeout(timeoutMs)
});

const rawText = await response.text();
let parsed;
try {
  parsed = rawText ? JSON.parse(rawText) : {};
} catch {
  parsed = { rawText };
}

if (!response.ok) {
  return [{
    json: {
      approved: false,
      status: 'error',
      score: 0,
      coachReply: `Groq a repondu ${response.status}.`,
      provider: 'n8n-pedago-groq',
      issues: [`Groq HTTP ${response.status}`],
      recommendations: ['Verifier la cle API, le quota, et la compatibilite du modele vision.'],
      receivedAt: $json.receivedAt,
      groqModel: $json.groqModel,
      groqRaw: parsed
    }
  }];
}

return [{
  json: {
    ...$json,
    groqRaw: parsed
  }
}];

if ($json.skippedGroq || !$json.groqRaw) {
  return [{ json: $json }];
}

const raw = $json.groqRaw;
const outputText = typeof raw.output_text === 'string'
  ? raw.output_text
  : Array.isArray(raw.output)
    ? raw.output
        .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
        .map((entry) => entry?.text || entry?.output_text || '')
        .filter(Boolean)
        .join('\n')
    : '';

let review = null;
try {
  review = outputText ? JSON.parse(outputText) : null;
} catch {
  const match = outputText.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      review = JSON.parse(match[0]);
    } catch {
      review = null;
    }
  }
}

if (!review || typeof review !== 'object') {
  return [{
    json: {
      approved: false,
      status: 'error',
      score: 0,
      coachReply: 'Reponse Groq invalide ou non parsable.',
      provider: 'n8n-pedago-groq',
      issues: ['Invalid JSON returned by Groq.'],
      recommendations: ['Verifier le prompt, le schema JSON et les logs d execution n8n.'],
      receivedAt: $json.receivedAt,
      groqModel: $json.groqModel,
      groqRaw: raw
    }
  }];
}

const approved = review.approved === true;
const status = ['approved', 'needs_revision', 'rejected', 'error'].includes(String(review.status))
  ? String(review.status)
  : (approved ? 'approved' : 'needs_revision');
const scoreValue = Number(review.score);
const score = Number.isFinite(scoreValue) ? Math.max(0, Math.min(100, scoreValue)) : (approved ? 80 : 35);
const coachReply = String(review.coachReply || '').trim() || (approved
  ? 'Exercice valide. Le module suivant peut etre debloque.'
  : 'Exercice recu, mais des ajustements sont necessaires.');
const issues = Array.isArray(review.issues) ? review.issues.filter((item) => typeof item === 'string').slice(0, 5) : [];
const recommendations = Array.isArray(review.recommendations)
  ? review.recommendations.filter((item) => typeof item === 'string').slice(0, 5)
  : [];

return [{
  json: {
    approved,
    status,
    score,
    coachReply,
    provider: `groq:${$json.groqModel}`,
    issues,
    recommendations,
    receivedAt: $json.receivedAt,
    moduleId: $json.moduleId,
    assetCount: $json.assetCount,
    expectedAssetCount: $json.expectedAssetCount,
    groqId: raw.id || null
  }
}];
